import{_ as a,o as t,c as o,al as r}from"./chunks/framework.-mVGFbqa.js";const i="/docs/assets/img/Material%20Home%20Component/Additional/Migration.png",m=JSON.parse('{"title":"📦 Migration to Material Component","description":"","frontmatter":{},"headers":[],"relativePath":"additional/migration-to-material.md","filePath":"additional/migration-to-material.md"}'),n={name:"additional/migration-to-material.md"};function s(l,e,d,c,h,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="📦-migration-to-material-component" tabindex="-1">📦 Migration to Material Component <a class="header-anchor" href="#📦-migration-to-material-component" aria-label="Permalink to &quot;📦 Migration to Material Component&quot;">​</a></h1><h3 id="🌟-overview" tabindex="-1">🌟 Overview <a class="header-anchor" href="#🌟-overview" aria-label="Permalink to &quot;🌟 Overview&quot;">​</a></h3><p>Welcome to the official Material Components guide. This documentation is designed to assist you with two separate processes:</p><ul><li><p><strong>Technical Migration</strong>: Transitioning from the legacy components (using the google- prefix) to the new, optimized architecture (using the material- prefix).</p></li><li><p><strong>Version Upgrade</strong>: Moving from the Free version to the Paid (PRO) version, unlocking advanced features, exclusive widgets, and deeper customization options.</p></li></ul><h2 id="🚀-migrate-from-google-cards-to-material-cards" tabindex="-1">🚀 Migrate from Google Cards to Material Cards <a class="header-anchor" href="#🚀-migrate-from-google-cards-to-material-cards" aria-label="Permalink to &quot;🚀 Migrate from Google Cards to Material Cards&quot;">​</a></h2><p>If you are using the <strong>old Google component</strong> in your Lovelace dashboards, you will need to <strong>update your configuration</strong> to the new <strong>Material Cards</strong> version.</p><p>This guide will walk you through the process step by step.</p><hr><h3 id="🔹-step-1-–-open-the-lovelace-dashboard" tabindex="-1">🔹 Step 1 – Open the Lovelace Dashboard <a class="header-anchor" href="#🔹-step-1-–-open-the-lovelace-dashboard" aria-label="Permalink to &quot;🔹 Step 1 – Open the Lovelace Dashboard&quot;">​</a></h3><ol><li>Go to the dashboard where your Google component cards are already added.</li><li>Click the <strong>menu</strong> (three dots in the top right corner).</li><li>Select <strong>Edit Dashboard</strong> → <strong>Raw Configuration Editor</strong> (or <em>Editor di configurazione testuale</em>).</li></ol><hr><h3 id="🔹-step-2-–-search-and-replace" tabindex="-1">🔹 Step 2 – Search and Replace <a class="header-anchor" href="#🔹-step-2-–-search-and-replace" aria-label="Permalink to &quot;🔹 Step 2 – Search and Replace&quot;">​</a></h3><ol><li><p>Open the <strong>search function</strong> in your editor: press <strong>Ctrl + F</strong> (or Cmd + F on macOS).</p></li><li><p>Search for all instances of:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>google-</span></span></code></pre></div></li><li><p>Replace them with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>material-</span></span></code></pre></div><p>This will rename your old component identifiers to the new Material Cards naming convention.</p></li></ol><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>📸 Example: In the attached screenshot, you can see how <code>google-button-card</code> should be renamed to <code>material-button-card</code>.</p></div><img src="'+i+'" alt=""><hr><h3 id="🔹-step-3-–-save-and-refresh" tabindex="-1">🔹 Step 3 – Save and Refresh <a class="header-anchor" href="#🔹-step-3-–-save-and-refresh" aria-label="Permalink to &quot;🔹 Step 3 – Save and Refresh&quot;">​</a></h3><ol><li>After updating all entries, click <strong>Save</strong> in the Raw Configuration Editor.</li><li>Refresh the dashboard to apply the changes.</li><li>Verify that all cards are functioning correctly with the new Material Cards.</li></ol><hr><h3 id="⚠️-notes" tabindex="-1">⚠️ Notes <a class="header-anchor" href="#⚠️-notes" aria-label="Permalink to &quot;⚠️ Notes&quot;">​</a></h3><ul><li>Make sure to only replace <strong>component names</strong>, not entity IDs or other configuration parameters.</li><li>The new Material Cards support additional features like <strong>Material Dialogs</strong> and <strong>Material Media</strong>, so you may want to explore those for enhanced functionality.</li></ul>',21)])])}const u=a(n,[["render",s]]);export{m as __pageData,u as default};
